#include<bits/stdc++.h>
using namespace std;
long long n,a[100010],la[100010],lb[100010],ra[100010],rb[100010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        scanf("%lld",&n);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
        }
        ra[n+1]=rb[n+1]=0;
        for(long long i=1;i<=n;i++)
        {
            if(lb[i-1]>=a[i])
            {
                lb[i]=a[i];
                la[i]=la[i-1];
            }
            else
            {
                lb[i]=a[i]-lb[i-1];
                la[i]=la[i-1]+lb[i];
            }
        }
        for(long long i=n;i>=1;i--)
        {
            if(rb[i+1]>=a[i])
            {
                rb[i]=a[i];
                ra[i]=ra[i+1];
            }
            else
            {
                rb[i]=a[i]-rb[i+1];
                ra[i]=ra[i+1]+rb[i];
            }
        }
        long long ans=LLONG_MAX;
        for(long long i=1;i<=n;i++)
        {
            // printf("i=%lld la[i]=%lld lb[i]=%lld ra[i]=%lld rb[i]=%lld\n",i,la[i],lb[i],ra[i],rb[i]);
            ans=min(ans,la[i-1]+ra[i+1]+max(0ll,a[i]-lb[i-1]-rb[i+1]));
        }
        printf("%lld\n",ans);
    }
    return 0;
}
